pragma solidity 0.8.17;

contract IUserModule {
    /**
     * @dev Returns total underlying assets of the vault.
     */
    function totalAssets() public view returns (uint256) {}

    /**
     * @dev See {IERC4626-deposit}.
     * @dev User function to deposit.
     * @param assets_ amount to supply.
     * @param receiver_ address to send iTokens to.
     * @return shares_ amount of iTokens sent to the `receiver_` address passed
     */
    function deposit(
        uint256 assets_,
        address receiver_
    ) public returns (uint256 shares_) {}

    /**
     * @dev See {IERC4626-mint}.
     * @dev User function to mint.
     * @param shares_ amount to iToken shares to mint.
     * @param receiver_ address to send iTokens to.
     * @return assets_ amount of underlying assets sent to the `receiver_` address passed
     */
    function mint(
        uint256 shares_,
        address receiver_
    ) public returns (uint256 assets_) {}

    /**
     * @dev See {IERC4626-withdraw}.
     * @dev User function to withdraw.
     * @param assets_ amount to withdraw.
     * @param receiver_ address to send withdrawn amount to.
     * @param owner_ address of owner whose shares will be burned.
     * @return shares_ amount of iTokens burned of owner.
     */
    function withdraw(
        uint256 assets_,
        address receiver_,
        address owner_
    ) public returns (uint256 shares_) {}

    /**
     * @dev See {IERC4626-redeem}.
     * @dev User function to redeem.
     * @param shares_ amount of shares to redeem.
     * @param receiver_ address to send underlying withdrawn amount to.
     * @param owner_ address of owner whose shares will be burned.
     * @return assetsAfterFee_ underlying tokens sent to the receiver after withdraw fee.
     */
    function redeem(
        uint256 shares_,
        address receiver_,
        address owner_
    ) public returns (uint256 assetsAfterFee_) {}

    /// Emitted whenever a user withdraws assets and a fee is collected.
    event LogWithdrawFeeCollected(address indexed payer, uint256 indexed fee);

    event Deposit(
        address indexed sender,
        address indexed owner,
        uint256 assets,
        uint256 shares
    );

    event Withdraw(
        address indexed sender,
        address indexed receiver,
        address indexed owner,
        uint256 assets,
        uint256 shares
    );
}

contract IRefinanceModule {
    /**
     * @notice Core function to perform refinance.
     * @param fromProtocolId_ Id of the protocol to refinance from.
     * @param toProtocolId_ Id of the protocol to refinance to.
     * @param route_ Route for flashloan. Flashloan will always be taken in `WSTETH`.
     * @param wstETHflashAmount_ Amount of flashloan.
     * @param wETHBorrowAmount_ Amount of wETH to be borrowed.
     * @param withdrawAmount_ Amount to be withdrawn. Will always be in stETH.
     * @return ratioFromProtocol_ Ratio of `from` protocol
     * @return ratioToProtocol_ Ratio of `to` protocol
     */
    function refinance(
        uint8 fromProtocolId_,
        uint8 toProtocolId_,
        uint256 route_,
        uint256 wstETHflashAmount_,
        uint256 wETHBorrowAmount_,
        uint256 withdrawAmount_
    ) external returns (uint256 ratioFromProtocol_, uint256 ratioToProtocol_) {}

    /// @notice Emitted whenever rebalancer refinances between 2 protocols.
    event LogRefinance(
        uint8 indexed protocolFrom,
        uint8 indexed protocolTo,
        uint256 indexed route,
        uint256 wstETHflashAmount,
        uint256 wETHBorrowAmount,
        uint256 withdrawAmount
    );
}

contract ILeverageDexModule {
    /// @notice Core function to perform DEX refinance.
    /// @dev Note Flashloan will always be taken in `WSTETH`.
    /// @param protocolId_ Id of the protocol to refinance from.
    /// @param route_ Route for flashloan.
    /// @param wstETHflashAmount_ Amount of flashloan.
    /// @param wETHBorrowAmount_ Amount of wETH to be borrowed.
    /// @param withdrawAmount_ Amount to be withdrawn. Will always be in stETH.
    /// @param perfectColShares_ The change in collateral shares (positive for deposit, negative for withdrawal)
    /// @param colToken0MinMax_ Min or max collateral amount of token0 to withdraw or deposit (positive for deposit, negative for withdrawal)
    /// @param colToken1MinMax_ Min or max collateral amount of token1 to withdraw or deposit (positive for deposit, negative for withdrawal)
    /// @param perfectDebtShares_ The change in debt shares (positive for borrowing, negative for repayment)
    /// @param debtToken0MinMax_ Min or max debt amount for token0 to borrow or payback (positive for borrowing, negative for repayment)
    /// @param debtToken1MinMax_ Min or max debt amount for token1 to borrow or payback (positive for borrowing, negative for repayment)
    function leverageDexRefinance(
        uint8 protocolId_,
        uint256 route_,
        uint256 wstETHflashAmount_,
        uint256 wETHBorrowAmount_,
        uint256 withdrawAmount_,
        int256 perfectColShares_,
        int256 colToken0MinMax_, // if +, max to deposit, if -, min to withdraw
        int256 colToken1MinMax_, // if +, max to deposit, if -, min to withdraw
        int256 perfectDebtShares_,
        int256 debtToken0MinMax_, // if +, min to borrow, if -, max to payback
        int256 debtToken1MinMax_ // if +, min to borrow, if -, max to payback
    ) external returns (uint256 ratioFromProtocol_, uint256 ratioToProtocol_) {}

    /// @notice Emitted whenever rebalancer refinances to fluid dex
    event LogLeverageDexRefinance(
        uint8 indexed protocolFrom,
        uint256 indexed route,
        uint256 wstETHflashAmount,
        uint256 wETHBorrowAmount,
        uint256 withdrawAmount,
        int256 perfectColShares,
        int256 colToken0MinMax,
        int256 colToken1MinMax,
        int256 perfectDebtShares,
        int256 debtToken0MinMax,
        int256 debtToken1MinMax
    );
}

contract IUnwindDexModule {
