    /// @param sellAmount_ Amount of KING to sell.
    /// @param unitAmount_ Amount of WETH to buy.
    /// @param swapConnectorName_ Name of the connector to use for the swap.
    /// @param swapCallData_ Call data for the swap.
    function swapKingTokensToWeth(
        uint256 sellAmount_,
        uint256 unitAmount_,
        string memory swapConnectorName_,
        bytes memory swapCallData_
    ) public {}

    /**
     * @notice Open function to sweep ideal `weth` to `weeth` in Dsa.
     */
    function sweepWethToWeEth() public {}

    /// @notice Transfers KING tokens to Team MS.
    /// @param amount_ Amount of KING to transfer.
    function transferKingTokensToTeamMS(uint256 amount_) public {}

    /// Emitted when stETH is deposited from vault to protocols.
    event LogVaultToProtocolDeposit(
        uint8 indexed protocol,
        uint256 depositAmount
    );

    /// Emitted whenever stETH is deposited from protocol
    /// to vault to craete withdrawal vaialability.
    event LogFillVaultAvailability(
        uint8 indexed protocol,
        uint256 withdrawAmount
    );

    /// Emitted whenever ideal Weth DSA balance is swapped to stETH.
    event LogWethSweep(uint256 wethAmount);

    /// Emitted whenever ideal Eth DSA balance is swapped to stETH.
    event LogEthSweep(uint256 ethAmount);

    /// @notice Emitted whenever ideal Weth DSA balance is swept to WEETH.
    event LogWethSweepToWeEth(uint256 wethAmount);

    /// @notice Emitted whenever King rewards are swapped.
    event LogSwapKingTokensToWeth(
        uint256 sellAmount,
        uint256 unitAmount,
        string swapConnectorName
    );

    /// Emitted whenever rebalancer refinances between 2 protocols.
    event LogCollectRevenue(uint256 amount, address indexed to);

    /// Emitted whenever exchange price is updated.
    event LogUpdateExchangePrice(
        uint256 indexed exchangePriceBefore,
        uint256 indexed exchangePriceAfter
    );

    /// @notice Emitted whenever King tokens are transferred to Team MS.
    event LogTransferKingTokensToTeamMS(
        uint256 indexed amount
    );
}

contract ILeverageModule {
    /* @notice Core function to perform leverage.
     * @dev Note Flashloan will always be taken in `WSTETH`.
     * @param protocolId_ Id of the protocol to leverage.
     * @param route_ Route for flashloan
     * @param wstETHflashAmount_ Amount of flashloan.
     * @param wETHBorrowAmount_ Amount of weth to be borrowed.
     * @param vaults_ Addresses of old vaults to deleverage.
     * @param vaultAmounts_ Amount of `WETH` that we will payback in old vaults.
     * @param swapMode_ Mode of swap.(0 = no swap, 1 = Swap Aggregator, 2 = direct Lido route)
     * @param _swapConnectors Array of swap aggregator connectors to route swap from.
     * @param _swapDatas Array of bytes calldata required for `WETH` to `WSTETH` swapping.
     * @param unitAmount_ `WSTETH` per `WETH` conversion ratio with slippage.
     * @dev Note `WETH` will always be swapped to `WSTETH`,
     * even if the protocol accepts STETH. (This is done to add simplicity to the vault).
     */
    function leverage(
        uint8 protocolId_,
        uint256 route_,
        uint256 wstETHflashAmount_,
        uint256 wETHBorrowAmount_,
        address[] memory vaults_,
        uint256[] memory vaultAmounts_,
        uint256 swapMode_,
        string[] memory _swapConnectors,
        bytes[] memory _swapDatas,
        uint256 unitAmount_
    ) external {}

    /// Emitted whenever a protocol is leveraged.
    event LogLeverage(
        uint8 indexed protocol,
        uint256 indexed route,
        uint256 wstETHflashAmt,
        uint256 ethAmountBorrow,
        address[] vaults,
        uint256[] vaultAmts,
        uint256 indexed swapMode,
        uint256 unitAmt,
        uint256 vaultSwapAmt
    );
}

