contract IFluidStethModule {
    /// @notice Core function to perform steth queueing refinance.
    /// @dev Note Flashloan will always be taken in `WETH` here.
    /// @param fromProtocolId_ Id of the protocol to refinance from.
    /// @param route_ Route for flashloan.
    /// @param wETHBorrowAmount_ Amount of wETH for flashloan and to be borrowed.
    /// @param withdrawStethAmount_ Amount of stETH to be withdrawn. Will always be in stETH.
    function queueSteth(
        uint8 fromProtocolId_,
        uint256 route_,
        uint256 wETHBorrowAmount_,
        uint256 withdrawStethAmount_
    ) external returns (uint256 ratioFromProtocol_) {}

    /// @notice Core function to claim ETH from stETH request.
    /// @dev Note After claiming ETH, it will be converted to WETH and sent to the vault.
    /// @param fromNftID_ NFT Id from which we have to start claiming.
    function claimSteth(
        uint256 fromNftID_
    ) external returns (uint256 claimed_) {}

    /// @notice Core function to claim ETH and Payback debt in fluid.
    /// @param fromNftID_ NFT Id from which we have to start claiming.
    function claimStethAndPaybackFluid(
        uint256 fromNftID_
    ) external returns (uint256 ethClaimed_) {}

    /// @notice Emitted when stETH goes for queueing.
    event LogQueueSteth(
        uint8 fromProtocolId,
        uint256 route,
        uint256 wETHBorrowAmount,
        uint256 withdrawStethAmount
    );

    /// @notice Emitted when stETH is claimed from stETH protocol.
    event LogClaimSteth(uint256 fromNFTId, uint256 ethClaimed);

    /// @notice Emitted when stETH is claimed and eth debt is paid back in fluid.
    event LogClaimStethAndPaybackFluid(uint256 fromNFTId, uint256 ethClaimed);
}

